// Function to calculate harmonic prefix sums and store them in an array
void computeHarmonicPrefixSums(int n, double *prefixSums) {
    for (int i = 1; i <= n; ++i) {
        prefixSums[i - 1] = 0.0;
        for (int j = 1; j <= i; ++j) {
            prefixSums[i - 1] += 1.0 / j;
        }
    }
}

int main(void) {
    int n;
    printf("Enter the value of n: ");
    scanf("%d", &n);

    // Allocate memory for the prefix sums array
    double *prefixSums = (double *)malloc(n * sizeof(double));

    if (prefixSums == NULL) {
        fprintf(stderr, "Memory allocation failed.\n");
        return 1;
    }

    // Compute harmonic prefix sums and store them in the array
    computeHarmonicPrefixSums(n, prefixSums);

    // Print all n values
    for (int i = 0; i < n; ++i) {
        printf("%.6f ", prefixSums[i]);
    }
    printf("\n");

    // Free allocated memory
    free(prefixSums);

    return 0;
}

